        [HttpPost("avatar")]
        [RequestSizeLimit(MaxAvatarSizeBytes)]
        public async Task<IActionResult> UploadAvatar(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest(new { error = "No file uploaded" });

            if (file.Length > MaxAvatarSizeBytes)
                return BadRequest(new { error = $"File size exceeds maximum allowed size of {MaxAvatarSizeBytes / 1024 / 1024}MB" });

            var validationResult = await ValidateFile(file, AllowedAvatarExtensions, true);
            if (!validationResult.IsValid)
                return BadRequest(new { error = validationResult.ErrorMessage });

            var savedPath = await SaveFile(file, "avatars", validationResult.Extension);
            return Ok(new { filePath = savedPath, fileName = Path.GetFileName(savedPath) });
        }

        [HttpPost("document")]
        [RequestSizeLimit(MaxDocumentSizeBytes)]
        public async Task<IActionResult> UploadDocument(IFormFile file)
        {
