            if (file.Length > MaxDocumentSizeBytes)
                return BadRequest(new { error = $"File size exceeds maximum allowed size of {MaxDocumentSizeBytes / 1024 / 1024}MB" });

            var validationResult = await ValidateFile(file, AllowedDocumentExtensions, false);
            if (!validationResult.IsValid)
                return BadRequest(new { error = validationResult.ErrorMessage });

