        private async Task<FileValidationResult> ValidateFile(IFormFile file, HashSet<string> allowedExtensions, bool isImage)
        {
            var originalExtension = Path.GetExtension(file.FileName)?.ToLowerInvariant();
            
            if (string.IsNullOrEmpty(originalExtension) || !allowedExtensions.Contains(originalExtension))
            {
                return new FileValidationResult 
                { 
                    IsValid = false, 
                    ErrorMessage = $"File type not allowed. Allowed types: {string.Join(", ", allowedExtensions)}" 
                };
            }

            using var stream = file.OpenReadStream();
            var headerBytes = new byte[8];
            await stream.ReadAsync(headerBytes, 0, headerBytes.Length);
            stream.Position = 0;

            var actualExtension = GetFileExtensionFromSignature(headerBytes);
            
            if (actualExtension == null)
            {
                return new FileValidationResult 
                { 
                    IsValid = false, 
                    ErrorMessage = "Unable to verify file type from content" 
                };
            }

            if (!allowedExtensions.Contains(actualExtension))
            {
                return new FileValidationResult 
                { 
                    IsValid = false, 
                    ErrorMessage = "File content does not match allowed file types" 
                };
            }

            if (isImage)
            {
                if (!await ValidateImageContent(stream))
                {
                    return new FileValidationResult 
                    { 
                        IsValid = false, 
                        ErrorMessage = "Invalid or corrupted image file" 
                    };
                }
            }
            else if (actualExtension == ".pdf")
            {
                if (!await ValidatePdfContent(stream))
                {
                    return new FileValidationResult 
                    { 
                        IsValid = false, 
                        ErrorMessage = "Invalid or potentially malicious PDF file" 
                    };
                }
            }

            return new FileValidationResult 
            { 
                IsValid = true, 
                Extension = actualExtension 
            };
        }

        private string GetFileExtensionFromSignature(byte[] headerBytes)
        {
            foreach (var signature in FileSignatures)
            {
                foreach (var magic in signature.Value)
                {
                    if (headerBytes.Take(magic.Length).SequenceEqual(magic))
                    {
                        return signature.Key;
                    }
                }
            }
            return null;
        }

        private async Task<bool> ValidateImageContent(Stream stream)
        {
            try
            {
                stream.Position = 0;
                var buffer = new byte[512];
                await stream.ReadAsync(buffer, 0, buffer.Length);
                
                var content = System.Text.Encoding.ASCII.GetString(buffer);
                if (content.Contains("<?php") || content.Contains("<script") || content.Contains("<%"))
                {
                    return false;
                }

                stream.Position = 0;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private async Task<bool> ValidatePdfContent(Stream stream)
        {
            try
            {
                stream.Position = 0;
                var buffer = new byte[1024];
                var bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length);
                
                var content = System.Text.Encoding.ASCII.GetString(buffer, 0, bytesRead);
                
                if (content.Contains("/JavaScript") || content.Contains("/JS") || 
                    content.Contains("/Launch") || content.Contains("/EmbeddedFile"))
                {
                    return false;
                }

                stream.Position = 0;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private async Task<string> SaveFile(IFormFile file, string subfolder, string extension)
        {
            var uploadsPath = Path.Combine("wwwroot", "uploads", subfolder);
            Directory.CreateDirectory(uploadsPath);

            var secureFileName = GenerateSecureFileName(extension);
            var fullPath = Path.Combine(uploadsPath, secureFileName);

            var absolutePath = Path.GetFullPath(fullPath);
            var absoluteUploadsPath = Path.GetFullPath(uploadsPath);
            
            if (!absolutePath.StartsWith(absoluteUploadsPath, StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Invalid file path detected");
            }

            using (var fileStream = new FileStream(fullPath, FileMode.Create, FileAccess.Write, FileShare.None))
            {
                await file.CopyToAsync(fileStream);
            }

            return $"/uploads/{subfolder}/{secureFileName}";
        }

        private string GenerateSecureFileName(string extension)
        {
            var timestamp = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds();
            var randomBytes = new byte[16];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(randomBytes);
            }
            var randomString = Convert.ToBase64String(randomBytes)
                .Replace("+", "")
                .Replace("/", "")
                .Replace("=", "")
                .Substring(0, 12);
            
            return $"{timestamp}_{randomString}{extension}";
        }

